def nb_rule(model, s, n, mm):
    from pyomo.environ import value, Constraint
    arcs = [k for k in model.darcs if value(model.darcs[k]) != 0]
    nm_set = set()
    inbound = {}
    outbound = {}
    for (a, b, md) in arcs:
        nm_set.add((a, md)); nm_set.add((b, md))
        outbound.setdefault((a, md), []).append(b)
        inbound.setdefault((b, md), []).append(a)
    modes_at = {}
    for (nd, md) in nm_set:
        modes_at.setdefault(nd, []).append(md)
    if (n, mm) not in nm_set:
        return Constraint.Skip
    inflow = sum(model.x[s, np, n, mm] for np in inbound.get((n, mm), []))
    inflow += sum(model.w[s, n, mm, mp] for mp in modes_at.get(n, []))
    if n == s:
        inflow += model.y[s, mm]
    outflow = sum(model.x[s, n, np, mm] for np in outbound.get((n, mm), []))
    if n in model.d:
        outflow += model.z[s, n, mm]
    outflow += sum(model.w[s, n, mp, mm] for mp in modes_at.get(n, []))
    return inflow >= outflow
model.nb = Constraint(model.s, model.n, model.m, rule=nb_rule)

def db_rule(model, s, dd):
    from pyomo.environ import value
    modes_at = {}
    for k in model.darcs:
        if value(model.darcs[k]) != 0:
            a, b, md = k
            modes_at.setdefault(a, set()).add(md)
            modes_at.setdefault(b, set()).add(md)
    return sum(model.z[s, dd, mm] for mm in modes_at.get(dd, [])) >= 1
model.db = Constraint(model.s, model.d, rule=db_rule)

def al_rule(model):
    from pyomo.environ import value
    modes_at = {}
    for k in model.darcs:
        if value(model.darcs[k]) != 0:
            a, b, md = k
            modes_at.setdefault(a, set()).add(md)
            modes_at.setdefault(b, set()).add(md)
    return model.phil == sum(model.lrate[mm] * model.y[s, mm]
                             for s in model.s for mm in modes_at.get(s, []))
model.al = Constraint(rule=al_rule)

